+                        pBuffer += in_tensor_ch;
+                        col_counter++;
+
+                        if (col_counter == tiling_size)
+                        {
+                            pOut = nn_mat_mul_kernel_tiling_asym_s8_s8_s8((int8_t *)tmp_buf,
+                                                                          src2,
+                                                                          dst_i32,
+                                                                          pOut,
+                                                                          out_scale,
+                                                                          out_shift,
+                                                                          col_counter,
+                                                                          in_tensor_ch,
+                                                                          out_tensor_ch,
+                                                                          out_offset,
+                                                                          act_min,
+                                                                          act_max,
+                                                                          contri_buf,
+                                                                          tiling_size);
+                            col_counter = 0;
+                            pBuffer = (int8_t *)tmp_buf;
+                        }
+                    }
+                }
+
+                pOut = nn_mat_mul_kernel_tiling_asym_s8_s8_s8((int8_t *)tmp_buf,
