 59→    /////////////////////////////////////////////////// START CALC CONTRI///////////////////////////////////////
 60→    // calculate the weight contribution
 61→    int32_t contri_buf[out_tensor_ch];
 62→    const int8_t *pWt = ker_weight;
 63→    long vl;
 64→    long maxvl_per_vg;
 65→    NDS_VEC_VSETVLI(maxvl_per_vg, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
