 71→        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
 72→        {
 73→            long in_tensor_ch2 = in_tensor_ch;
 74→            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 75→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);     // init the acculators
 76→            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 77→            NDS_VEC_VMV_V_I(NDS_VEC_V16, 1);                // const one for vd4dot
 78→
 79→            while (in_tensor_ch2 >= maxvl_per_vg)
 80→            {
 81→                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 82→                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
 83→                pWt += vl;
 84→                in_tensor_ch2 -= vl;
 85→
 86→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 87→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
 88→            }
 89→
 90→            //clean one of the dot product source
 91→            long tmp_vl = in_tensor_ch2 + 3;
 92→            NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 93→            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
